blob=''''''
# remove whitespace/newlines just in case
s=blob.strip().replace('\n','')
length=len(s)
blocks=length/168
print('Total chars:',length)
print('Exact division?', length%168==0)
print('Blocks (float):',blocks)
print('Blocks (int):', int(blocks))

# produce trimmed (10 full) and padded (11 full) variants
full10= s[:168*10]
remainder = s[168*10:]
pad_len = 168 - len(remainder) if remainder else 0
padded11 = s + ('0'*pad_len)
print('Remainder chars:', len(remainder))
print('Pad needed for next block:', pad_len)
print('Trimmed10 length:', len(full10))
print('Padded11 length:', len(padded11))

with open('trimmed10_sfx.txt','w') as f:
	f.write('[sfx]' + full10 + '[/sfx]')
with open('padded11_sfx.txt','w') as f:
	f.write('[sfx]' + padded11 + '[/sfx]')
print('Wrote trimmed10_sfx.txt and padded11_sfx.txt')
